          <div className="flex justify-center items-center mb-4">
            <h1 className="text-3xl font-bold text-gray-900 text-center">리뷰목록</h1>
            <span className="text-gray-600 text-center ml-2">총 {reviews.length}개의 리뷰</span>
          </div>
          <p className="text-gray-600 text-center">실제로 구매하신 고객님들의 후기를 확인해보세요.</p>
        </div>

        {/* Review List */}
        <div className="space-y-8">
          {pagedReviews.map(review => (
            <div key={review.id} className="bg-white rounded-lg shadow p-6">
              <div className="flex items-center mb-2">
                <span className="font-semibold text-blue-600 mr-2">{review.user}</span>
                <span className="text-xs text-gray-400">{review.time}</span>
              </div>
              <div className="mb-2 text-gray-900">{review.content}</div>
              <div className="text-xs text-gray-500 mb-2">{review.product}</div>
              {review.reply && (
                <div className="bg-gray-50 border-l-4 border-blue-400 p-3 text-sm text-gray-700 mt-2">
                  <span className="font-bold text-blue-600">애드모어</span> <span className="ml-2">{review.reply}</span>
                </div>
              )}
            </div>
          ))}
        </div>

        {/* Pagination */}
        <div className="flex justify-center mt-10 space-x-1">
          <button
            className="px-3 py-2 rounded bg-white border text-gray-700 disabled:opacity-50"
            onClick={() => handlePageChange(currentPage - 1)}
            disabled={currentPage === 1}
          >
            이전
          </button>
          {pageNumbers[0] > 1 && (
            <>
              <button
                className={`px-3 py-2 rounded border bg-white text-gray-700 border-gray-300`}
                onClick={() => handlePageChange(1)}
              >
                1
              </button>
              {pageNumbers[0] > 2 && <span className="px-2 py-2 text-gray-400">...</span>}
            </>
          )}
          {pageNumbers.map(page => (
            <button
              key={page}
              className={`px-3 py-2 rounded border ${
                page === currentPage
                  ? 'bg-blue-600 text-white border-blue-600'
                  : 'bg-white text-gray-700 border-gray-300'
              }`}
              onClick={() => handlePageChange(page)}
            >
              {page}
            </button>
          ))}
          {pageNumbers[pageNumbers.length - 1] < totalPages && (
            <>
              {pageNumbers[pageNumbers.length - 1] < totalPages - 1 && <span className="px-2 py-2 text-gray-400">...</span>}
              <button
                className={`px-3 py-2 rounded border bg-white text-gray-700 border-gray-300`}
                onClick={() => handlePageChange(totalPages)}
              >
                {totalPages}
              </button>
            </>
          )}
          <button
            className="px-3 py-2 rounded bg-white border text-gray-700 disabled:opacity-50"
            onClick={() => handlePageChange(currentPage + 1)}
            disabled={currentPage === totalPages}
          >
            다음
          </button>
        </div>
      </div>
    </div>
  );
};

export default Reviews;
